  }, [state.phase]);

  const handlePieceSelect = (type: PieceType) => {
    if (state.phase !== 'PLAYING' || state.targetSquare === null) return;

    // Logic: Is there an invisible piece of this type that can reach the target square?
    const validPiece = state.pieces.find(p => p.type === type && canPieceReach(p.square, state.targetSquare!, p.type));

    if (validPiece) {
      const oldSquare = validPiece.square;
      const newSquare = state.targetSquare!;

      const updatedPieces = state.pieces.map(p => 
        p.id === validPiece.id ? { ...p, square: newSquare } : p
      );

      setDisabledOptions([]);
      const nextTarget = generateNewTarget(updatedPieces);

      setState(prev => ({
        ...prev,
        score: prev.score + 10,
        pieces: updatedPieces,
        lastMoveLine: [oldSquare, newSquare],
        targetSquare: nextTarget,
      }));
    } else {
      // Error feedback trigger
      setIsShaking(true);
      setTimeout(() => setIsShaking(false), 300);

      setDisabledOptions(prev => [...prev, type]);
      setState(prev => {
        const newStrikes = prev.strikes + 1;
        if (newStrikes >= MAX_STRIKES) {
          clearInterval(timerRef.current!);
          return { ...prev, strikes: newStrikes, phase: 'GAMEOVER' };
        }
        return { ...prev, strikes: newStrikes };
      });
    }
  };

  const renderStartScreen = () => (
    <div className="flex flex-col items-center justify-center h-full space-y-12 animate-in fade-in duration-1000">
      <div className="text-center">
        <h1 className="text-5xl font-extralight tracking-[0.3em] mb-4 text-slate-100 uppercase">Academy Drill</h1>
        <p className="text-amber-700 font-bold tracking-[0.5em] text-[10px] uppercase">Venture Chess Visualization Trainer</p>
      </div>

      <div className="grid grid-cols-1 gap-4 w-72">
        <button 
          onClick={() => startGame(Difficulty.EASY)}
          className="group relative border border-slate-800 bg-slate-900/50 py-4 px-6 hover:bg-slate-800 transition-all uppercase tracking-[0.2em] text-[10px] font-bold text-slate-400 hover:text-white"
        >
          <span className="relative z-10">Level I: Two Pieces</span>
        </button>
        <button 
          onClick={() => startGame(Difficulty.INTERMEDIATE)}
          className="group relative border border-slate-800 bg-slate-900/50 py-4 px-6 hover:bg-slate-800 transition-all uppercase tracking-[0.2em] text-[10px] font-bold text-slate-400 hover:text-white"
        >
          <span className="relative z-10">Level II: Three Pieces</span>
        </button>
        <button 
          onClick={() => startGame(Difficulty.HARD)}
          className="group relative border border-slate-800 bg-slate-900/50 py-4 px-6 hover:bg-slate-800 transition-all uppercase tracking-[0.2em] text-[10px] font-bold text-slate-400 hover:text-white"
        >
          <span className="relative z-10">Level III: Four Pieces</span>
        </button>
      </div>
    </div>
  );

  const renderGameScreen = () => (
    <div className="flex flex-col items-center w-full max-w-6xl px-4 animate-in fade-in duration-500">
      {/* HUD Bar */}
      <div className="flex justify-between items-center w-full max-w-[600px] mb-6 font-mono text-xs tracking-widest text-slate-500 border-b border-slate-800 pb-4">
        <div className="flex space-x-12">
          <div className="flex flex-col">
            <span className="text-[8px] text-slate-700 mb-1">CUMULATIVE SCORE</span>
            <span className="text-slate-200 text-lg font-bold">{state.score.toString().padStart(4, '0')}</span>
          </div>
          <div className="flex flex-col">
            <span className="text-[8px] text-slate-700 mb-1">SESSION TIME</span>
            <span className={`text-lg font-bold ${state.timeLeft < 15 ? 'text-amber-600' : 'text-slate-200'}`}>
              {Math.floor(state.timeLeft / 60)}:{(state.timeLeft % 60).toString().padStart(2, '0')}
            </span>
          </div>
        </div>

        <div className="flex flex-col items-end">
          <span className="text-[8px] text-slate-700 mb-2">INTEGRITY STRIKES</span>
          <div className="flex space-x-1.5">
            {Array.from({ length: MAX_STRIKES }).map((_, i) => (
              <div 
                key={i} 
                className={`w-4 h-1 transition-colors duration-300 ${i < state.strikes ? 'bg-amber-700' : 'bg-slate-800'}`} 
              />
            ))}
          </div>
        </div>
      </div>

      {/* Central Chessboard with Error Shake Wrapper */}
      <div className={isShaking ? 'animate-soft-shake' : ''}>
        <ChessBoard 
          pieces={state.pieces} 
          targetSquare={state.targetSquare} 
          lastMoveLine={state.lastMoveLine} 
        />
      </div>

      {/* Piece Selection Interface */}
      <div className="mt-8 flex flex-col items-center">
        <div className={`flex justify-center space-x-4 transition-opacity duration-300 ${state.phase !== 'PLAYING' ? 'opacity-10 pointer-events-none' : 'opacity-100'}`}>
          {(['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'] as PieceType[]).map((type) => {
            const isUsedInSession = state.pieces.some(p => p.type === type);
            const isDisabled = disabledOptions.includes(type);

            return (
              <button
                key={type}
                onClick={() => handlePieceSelect(type)}
                disabled={isDisabled || !isUsedInSession}
                className={`w-20 h-20 p-4 border border-slate-800 rounded-sm transition-all bg-slate-900/20 hover:bg-slate-800 active:scale-95 flex flex-col items-center justify-center ${isDisabled ? 'opacity-10 grayscale' : 'opacity-100'} ${!isUsedInSession ? 'hidden' : ''}`}
              >
                <div className="w-10 h-10 filter invert opacity-80 brightness-200 mb-1">
                  {PIECE_ICONS[type]}
                </div>
                <span className="text-[8px] text-slate-600 font-bold uppercase tracking-tighter">{type}</span>
              </button>
            );
          })}
        </div>

        {state.phase === 'OBSERVING' ? (
          <div className="mt-6 text-amber-700 text-[10px] font-bold uppercase tracking-[0.5em] animate-pulse">
            Observation Phase: Memorize All Pieces
          </div>
        ) : (
          <div className="mt-6 text-slate-600 text-[9px] font-medium uppercase tracking-[0.3em] h-4">
            Which piece can move to the highlighted square?
          </div>
        )}
      </div>
    </div>
  );

  const renderGameOver = () => (
    <div className="flex flex-col items-center justify-center h-full space-y-16 animate-in fade-in zoom-in duration-1000">
      <div className="text-center">
        <h2 className="text-5xl font-extralight tracking-[0.3em] mb-4 text-slate-100 uppercase">Session Over</h2>
        <p className="text-slate-600 uppercase tracking-[0.4em] text-[10px] font-bold">Analysis Terminated</p>
      </div>

      <div className="flex flex-col items-center space-y-2">
        <div className="text-slate-500 uppercase tracking-[0.5em] text-[8px] font-bold">Performance Rating</div>
        <div className="text-8xl font-black text-amber-600 tracking-tighter">{state.score}</div>
      </div>

      <div className="flex space-x-6">
        <button 
          onClick={() => startGame(state.difficulty)}
          className="border border-slate-700 text-slate-200 py-4 px-10 text-[10px] font-bold uppercase tracking-[0.3em] hover:bg-slate-800 transition-all"
        >
          Retry Drill
        </button>
        <button 
          onClick={() => setState(prev => ({ ...prev, phase: 'START' }))}
          className="bg-slate-200 text-slate-950 py-4 px-10 text-[10px] font-bold uppercase tracking-[0.3em] hover:bg-white transition-all shadow-xl"
        >
          Exit to Hub
        </button>
      </div>
    </div>
  );

  return (
    <div className="relative min-h-screen w-full bg-[#0F172A] flex items-center justify-center overflow-hidden">
      <div className="parchment-grain absolute inset-0 z-0" />
      <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_200px_rgba(0,0,0,0.9)] z-10" />

      <main className="relative z-20 w-full h-full flex flex-col items-center py-12">
        {state.phase === 'START' && renderStartScreen()}
        {(state.phase === 'OBSERVING' || state.phase === 'PLAYING') && renderGameScreen()}
        {state.phase === 'GAMEOVER' && renderGameOver()}
      </main>

      <div className="absolute top-12 left-12 flex flex-col opacity-20 pointer-events-none hidden lg:flex">
        <div className="text-[10px] text-slate-500 font-bold uppercase tracking-[1em]">Venture</div>
        <div className="text-[10px] text-slate-500 font-bold uppercase tracking-[1em]">Academy</div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { Piece } from '../types';
import { PALETTE, PIECE_ICONS } from '../constants';

interface ChessBoardProps {
  pieces: Piece[];
  targetSquare: number | null;
  lastMoveLine: [number, number] | null;
}

const ChessBoard: React.FC<ChessBoardProps> = ({ pieces, targetSquare, lastMoveLine }) => {
  const ranks = ['8', '7', '6', '5', '4', '3', '2', '1'];
  const files = ['a', 'b', 'c', 'd', 'e', 'f', 'g', 'h'];

  const getSquareColor = (idx: number) => {
    const row = Math.floor(idx / 8);
    const col = idx % 8;
    return (row + col) % 2 === 0 ? PALETTE.BOARD_LIGHT : PALETTE.BOARD_DARK;
  };

  const getCoordinatesForLine = (idx: number) => {
    const row = Math.floor(idx / 8);
    const col = idx % 8;
    return {
      x: col * 12.5 + 6.25,
      y: row * 12.5 + 6.25,
    };
  };

  return (
    <div 
      className="relative p-6 rounded-sm border"
      style={{ 
        backgroundColor: `${PALETTE.SECONDARY_BG}40`, 
        borderColor: PALETTE.MUTED_ELEMENTS 
      }}
    >
      {/* File Labels (Top) */}
      <div className="flex w-full mb-1 pl-4 pr-4">
        {files.map(f => (
          <div 
            key={f} 
            className="flex-1 text-center text-[10px] font-bold uppercase tracking-widest"
            style={{ color: PALETTE.MUTED_ELEMENTS }}
          >{f}</div>
        ))}
      </div>

      <div className="flex">
        {/* Rank Labels (Left) */}
        <div className="flex flex-col mr-1 h-[300px] sm:h-[400px] md:h-[500px]">
          {ranks.map(r => (
            <div 
              key={r} 
              className="flex-1 flex items-center justify-center text-[10px] font-bold"
              style={{ color: PALETTE.MUTED_ELEMENTS }}
            >{r}</div>
          ))}
        </div>

        {/* Literal 8x8 Chessboard */}
        <div 
          className="relative aspect-square w-[300px] sm:w-[400px] md:w-[500px] border-4 rounded-sm overflow-hidden select-none"
          style={{ borderColor: PALETTE.MUTED_ELEMENTS }}
        >
          {/* Grid of 64 distinct squares */}
          <div className="grid grid-cols-8 grid-rows-8 w-full h-full">
            {Array.from({ length: 64 }).map((_, i) => (
              <div
                key={i}
                style={{ backgroundColor: getSquareColor(i) }}
                className="relative flex items-center justify-center"
              >
                {/* Highlighted Target Square */}
                {targetSquare === i && (
                  <div 
                    className="absolute inset-0 border-[3px] pointer-events-none z-10" 
                    style={{ borderColor: PALETTE.HIGHLIGHT_OUTLINE }}
                  />
                )}
              </div>
            ))}
          </div>

          {/* Pieces Layer */}
          <div className="absolute inset-0 grid grid-cols-8 grid-rows-8 pointer-events-none">
            {Array.from({ length: 64 }).map((_, i) => {
              const piece = pieces.find((p) => p.square === i);
              return (
                <div key={i} className="flex items-center justify-center p-1">
                  {piece && piece.isVisible && (
                    <div className="w-[85%] h-[85%] transition-opacity duration-1000">
                      {PIECE_ICONS[piece.type]}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          {/* Move Line Layer */}
          {lastMoveLine && (
            <svg className="absolute inset-0 w-full h-full pointer-events-none z-20" viewBox="0 0 100 100">
              <line
                x1={getCoordinatesForLine(lastMoveLine[0]).x}
                y1={getCoordinatesForLine(lastMoveLine[0]).y}
                x2={getCoordinatesForLine(lastMoveLine[1]).x}
                y2={getCoordinatesForLine(lastMoveLine[1]).y}
                stroke={PALETTE.PATH_INDICATOR}
                strokeWidth="0.4"
                className="opacity-60"
                style={{ strokeDasharray: '0.5, 0.5' }}
              />
            </svg>
          )}
        </div>

        {/* Rank Labels (Right) */}
        <div className="flex flex-col ml-1 h-[300px] sm:h-[400px] md:h-[500px]">
          {ranks.map(r => (
            <div 
              key={r} 
              className="flex-1 flex items-center justify-center text-[10px] font-bold"
              style={{ color: PALETTE.MUTED_ELEMENTS }}
            >{r}</div>
          ))}
        </div>
      </div>

      {/* File Labels (Bottom) */}
      <div className="flex w-full mt-1 pl-4 pr-4">
        {files.map(f => (
          <div 
            key={f} 
            className="flex-1 text-center text-[10px] font-bold uppercase tracking-widest"
            style={{ color: PALETTE.MUTED_ELEMENTS }}
          >{f}</div>
        ))}
      </div>
    </div>
  );
};

