      pieces: selectedPieces,
      targetSquare: null,
      score: 0,
      strikes: 0,
      timeLeft: START_TIME,
      lastMoveLine: null,
      correctMoves: 0,
      currentStreak: 0,
      bestStreak: 0,
    });

    setTimeout(() => {
      setState(prev => {
        const nextTarget = generateNewTarget(prev.pieces);
        return {
          ...prev,
          phase: 'PLAYING',
          pieces: prev.pieces.map(p => ({ ...p, isVisible: false })),
          targetSquare: nextTarget,
        };
      });
    }, OBSERVATION_TIME * 1000);
  };

  useEffect(() => {
    if (state.phase === 'PLAYING') {
      timerRef.current = setInterval(() => {
        setState(prev => {
          if (prev.timeLeft <= 1) {
            clearInterval(timerRef.current!);
            return { ...prev, timeLeft: 0, phase: 'GAMEOVER' };
          }
          return { ...prev, timeLeft: prev.timeLeft - 1 };
        });
      }, 1000);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [state.phase]);

  useEffect(() => {
    if (state.lastMoveLine) {
      const timer = setTimeout(() => {
        setState(prev => ({ ...prev, lastMoveLine: null }));
      }, 1000);
      return () => clearTimeout(timer);
    }
  }, [state.lastMoveLine]);

  // Clear move feedback after 1 second
  useEffect(() => {
    if (moveFeedback) {
      const timer = setTimeout(() => setMoveFeedback(null), 1000);
      return () => clearTimeout(timer);
    }
  }, [moveFeedback]);

  const handlePieceSelect = (type: PieceType) => {
    if (state.phase !== 'PLAYING' || state.targetSquare === null) return;

    const validPiece = state.pieces.find(p => p.type === type && canPieceReach(p.square, state.targetSquare!, p.type));

    if (validPiece) {
      const oldSquare = validPiece.square;
      const newSquare = state.targetSquare!;

      const updatedPieces = state.pieces.map(p => 
        p.id === validPiece.id ? { ...p, square: newSquare } : p
      );

      setDisabledOptions([]);
      setMoveFeedback({ type, status: 'correct' });
      const nextTarget = generateNewTarget(updatedPieces);

      setState(prev => {
        const newStreak = prev.currentStreak + 1;
        return {
          ...prev,
          score: prev.score + 10,
          pieces: updatedPieces,
          lastMoveLine: [oldSquare, newSquare],
          targetSquare: nextTarget,
          correctMoves: prev.correctMoves + 1,
          currentStreak: newStreak,
          bestStreak: Math.max(prev.bestStreak, newStreak),
        };
      });
    } else {
      setPulsingPiece(type);
      setMoveFeedback({ type, status: 'incorrect' });
      setTimeout(() => setPulsingPiece(null), 400);

      setDisabledOptions(prev => [...prev, type]);
      setState(prev => {
        const newStrikes = prev.strikes + 1;
        if (newStrikes >= MAX_STRIKES) {
          clearInterval(timerRef.current!);
          return { ...prev, strikes: newStrikes, phase: 'GAMEOVER', currentStreak: 0 };
        }
        return { ...prev, strikes: newStrikes, currentStreak: 0 };
      });
    }
  };

  const renderStartScreen = () => (
    <div className="flex flex-col items-center justify-center min-h-[80vh] space-y-12 animate-in fade-in duration-1000">
      <div className="text-center">
        <h1 
          className="text-5xl font-extralight tracking-[0.3em] mb-4 uppercase"
          style={{ color: PALETTE.PRIMARY_TEXT }}
        >Academy Drill</h1>
        <p 
          className="font-bold tracking-[0.5em] text-[10px] uppercase"
          style={{ color: PALETTE.HIGHLIGHT_OUTLINE }}
        >Venture Chess Visualization Trainer</p>
      </div>

      <div className="grid grid-cols-1 gap-4 w-72">
        {[
          { id: Difficulty.EASY, label: 'Level I: Two Pieces' },
          { id: Difficulty.INTERMEDIATE, label: 'Level II: Three Pieces' },
          { id: Difficulty.HARD, label: 'Level III: Four Pieces' }
        ].map(diff => (
          <button 
            key={diff.id}
            onClick={() => startGame(diff.id)}
            className="border py-4 px-6 transition-all uppercase tracking-[0.2em] text-[10px] font-bold shadow-sm"
            style={{ 
              backgroundColor: PALETTE.SECONDARY_BG,
              borderColor: PALETTE.MUTED_ELEMENTS,
              color: PALETTE.MUTED_ELEMENTS
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.backgroundColor = PALETTE.PRIMARY_TEXT;
              e.currentTarget.style.color = '#FFFFFF';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.backgroundColor = PALETTE.SECONDARY_BG;
              e.currentTarget.style.color = PALETTE.MUTED_ELEMENTS;
            }}
          >
            {diff.label}
          </button>
        ))}
      </div>
    </div>
  );

  const renderGameScreen = () => (
    <div className="flex flex-col items-center w-full max-w-6xl px-4 animate-in fade-in duration-500 pb-20">
      <div className="w-full max-w-[620px] mt-8 mb-4 font-mono select-none">
        <div className="flex justify-between items-end pb-3 px-2">
          <div className="flex space-x-16">
            <div className="flex flex-col">
              <span className="text-[10px] font-bold tracking-widest uppercase mb-2 opacity-60" style={{ color: PALETTE.PRIMARY_TEXT }}>SCORE</span>
              <span className="text-2xl font-black tracking-tight" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.score.toString().padStart(4, '0')}</span>
            </div>
            <div className="flex flex-col">
              <span className="text-[10px] font-bold tracking-widest uppercase mb-2 opacity-60" style={{ color: PALETTE.PRIMARY_TEXT }}>TIME</span>
              <span className="text-2xl font-black tracking-tight" style={{ color: state.timeLeft < 15 ? '#EF4444' : PALETTE.PRIMARY_TEXT }}>
                {Math.floor(state.timeLeft / 60)}:{(state.timeLeft % 60).toString().padStart(2, '0')}
              </span>
            </div>
          </div>

          <div className="flex flex-col items-end">
            <span className="text-[10px] font-bold tracking-widest uppercase mb-3 opacity-60" style={{ color: PALETTE.PRIMARY_TEXT }}>STRIKES</span>
            <div className="flex space-x-2">
              {Array.from({ length: MAX_STRIKES }).map((_, i) => (
                <div 
                  key={i} 
                  className="w-8 h-1.5 transition-all duration-300"
                  style={{ 
                    backgroundColor: i < state.strikes ? '#EF4444' : `${PALETTE.MUTED_ELEMENTS}25`,
                    transform: i < state.strikes ? 'scaleY(1.2)' : 'scaleY(1)'
                  }} 
                />
              ))}
            </div>
          </div>
        </div>
        <div className="w-full h-[1px] opacity-20" style={{ backgroundColor: PALETTE.PRIMARY_TEXT }} />
      </div>

      <ChessBoard 
        pieces={state.pieces} 
        targetSquare={state.targetSquare} 
        lastMoveLine={state.lastMoveLine} 
      />

      <div className="mt-10 flex flex-col items-center w-full max-w-[620px]">
        <div 
          className="flex justify-center space-x-4 w-full p-6 border rounded-sm"
          style={{ 
            borderColor: `${PALETTE.MUTED_ELEMENTS}10`,
            backgroundColor: PALETTE.SECONDARY_BG,
            opacity: state.phase !== 'PLAYING' ? 0.2 : 1 
          }}
        >
          {(['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'] as PieceType[]).map((type) => {
            const isUsedInSession = state.pieces.some(p => p.type === type);
            const isDisabled = disabledOptions.includes(type);
            const isPulsing = pulsingPiece === type;
            const feedback = moveFeedback?.type === type ? moveFeedback : null;

            if (!isUsedInSession) return null;

            return (
              <button
                key={type}
                onClick={() => handlePieceSelect(type)}
                disabled={isDisabled}
                className={`relative w-28 h-32 p-3 border transition-all active:scale-95 flex flex-col items-center justify-between rounded-sm ${isPulsing ? 'animate-subtle-pulse' : ''}`}
                style={{ 
                  backgroundColor: PALETTE.SECONDARY_BG,
                  borderColor: isPulsing ? '#EF4444' : `${PALETTE.MUTED_ELEMENTS}20`,
                  opacity: isDisabled && !feedback && !isPulsing ? 0.3 : 1,
                  boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)'
                }}
              >
                {/* Feedback Overlay */}
                {feedback && (
                  <div className={`absolute inset-0 flex items-center justify-center z-10 rounded-sm bg-white/40 backdrop-blur-[1px] animate-in fade-in duration-200`}>
                    {feedback.status === 'correct' ? (
                      <svg className="w-12 h-12 text-green-500 drop-shadow-sm" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="4">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                      </svg>
                    ) : (
                      <svg className="w-12 h-12 text-red-500 drop-shadow-sm" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="4">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                      </svg>
                    )}
                  </div>
                )}

                <div className="w-full h-20 flex items-center justify-center">
                  <div className="w-16 h-16">
                    {PIECE_ICONS[type]}
                  </div>
                </div>
                <span className="text-[11px] font-bold uppercase tracking-widest pt-2 border-t w-full text-center" style={{ color: PALETTE.MUTED_ELEMENTS, borderColor: `${PALETTE.MUTED_ELEMENTS}10` }}>{type}</span>
              </button>
            );
          })}
        </div>

        <div 
          className="mt-8 text-[11px] font-bold uppercase tracking-[0.5em] text-center opacity-60"
          style={{ color: state.phase === 'OBSERVING' ? PALETTE.HIGHLIGHT_OUTLINE : PALETTE.PRIMARY_TEXT }}
        >
          {state.phase === 'OBSERVING' ? 'MEMORIZE PIECE LOCATIONS' : 'CHOOSE THE PIECE THAT CAN REACH THE HIGHLIGHTED SQUARE'}
        </div>
      </div>
    </div>
  );

  const renderGameOver = () => (
    <div className="flex flex-col items-center justify-center min-h-[80vh] space-y-12 animate-in fade-in zoom-in duration-1000">
      <div className="text-center">
        <h2 className="text-5xl font-extralight tracking-[0.3em] mb-4 uppercase" style={{ color: PALETTE.PRIMARY_TEXT }}>Session Over</h2>
        <p className="uppercase tracking-[0.4em] text-[10px] font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>Analysis Terminated</p>
      </div>

      <div className="flex flex-col items-center space-y-2">
        <div className="uppercase tracking-[0.5em] text-[8px] font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>Performance Rating</div>
        <div className="text-8xl font-black tracking-tighter" style={{ color: PALETTE.HIGHLIGHT_OUTLINE }}>{state.score}</div>
      </div>

      <div className="flex flex-col items-center space-y-4 w-full max-w-sm">
        <div className="flex justify-between w-full border-b pb-2" style={{ borderColor: `${PALETTE.MUTED_ELEMENTS}40` }}>
          <span className="uppercase tracking-[0.3em] text-[9px] font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>Correct Sequence</span>
          <span className="text-xs font-mono font-bold" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.correctMoves}</span>
        </div>
        <div className="flex justify-between w-full border-b pb-2" style={{ borderColor: `${PALETTE.MUTED_ELEMENTS}40` }}>
          <span className="uppercase tracking-[0.3em] text-[9px] font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>Peak Accuracy Streak</span>
          <span className="text-xs font-mono font-bold" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.bestStreak}</span>
        </div>
      </div>

      <div className="flex space-x-6 pt-4">
        <button 
          onClick={() => startGame(state.difficulty)}
          className="border py-4 px-10 text-[10px] font-bold uppercase tracking-[0.3em] transition-all shadow-sm"
          style={{ borderColor: PALETTE.MUTED_ELEMENTS, color: PALETTE.PRIMARY_TEXT }}
        >
          Retry Drill
        </button>
        <button 
          onClick={() => setState(prev => ({ ...prev, phase: 'START' }))}
          className="py-4 px-10 text-[10px] font-bold uppercase tracking-[0.3em] transition-all shadow-md"
          style={{ backgroundColor: PALETTE.PRIMARY_TEXT, color: '#FFFFFF' }}
        >
          Exit to Hub
        </button>
      </div>
    </div>
  );

  return (
    <div className="relative min-h-screen w-full flex flex-col items-center overflow-x-hidden" style={{ backgroundColor: PALETTE.PRIMARY_BG }}>
      <button 
        onClick={toggleFullscreen}
        className="fixed top-8 right-8 z-50 p-3 bg-white border border-gray-200 shadow-sm rounded-sm hover:bg-gray-50 transition-colors group"
        title={isFullscreen ? "Exit Fullscreen" : "Enter Fullscreen"}
      >
        {isFullscreen ? (
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={PALETTE.PRIMARY_TEXT} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M8 3v3a2 2 0 0 1-2 2H3m18 0h-3a2 2 0 0 1-2-2V3m0 18v-3a2 2 0 0 1 2-2h3M3 16h3a2 2 0 0 1 2 2v3"/>
          </svg>
        ) : (
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={PALETTE.PRIMARY_TEXT} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M15 3h6v6M9 21H3v-6M21 3l-7 7M3 21l7-7"/>
          </svg>
        )}
      </button>

      <main className="relative z-20 w-full h-full flex flex-col items-center flex-grow">
        {state.phase === 'START' && renderStartScreen()}
        {(state.phase === 'OBSERVING' || state.phase === 'PLAYING') && renderGameScreen()}
        {state.phase === 'GAMEOVER' && renderGameOver()}
      </main>

      <div className="fixed top-8 left-8 flex flex-col opacity-20 pointer-events-none hidden xl:flex">
        <div className="text-[10px] font-bold uppercase tracking-[1em]" style={{ color: PALETTE.MUTED_ELEMENTS }}>Venture</div>
        <div className="text-[10px] font-bold uppercase tracking-[1em]" style={{ color: PALETTE.MUTED_ELEMENTS }}>Academy</div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, GamePhase, Difficulty, Piece, PieceType } from './types';
import { getRandomSquare, getLegalMoves, canPieceReach } from './services/chessLogic';
import { PALETTE, PIECE_ICONS } from './constants';
import ChessBoard from './components/ChessBoard';

const OBSERVATION_TIME = 5;
const START_TIME = 180; 
const MAX_STRIKES = 5;

const App: React.FC = () => {
  const [state, setState] = useState<GameState>({
    phase: 'START',
    difficulty: Difficulty.EASY,
    pieces: [],
    targetSquare: null,
    score: 0,
    strikes: 0,
    timeLeft: START_TIME,
    lastMoveLine: null,
    correctMoves: 0,
    currentStreak: 0,
    bestStreak: 0,
  });

  const [isFullscreen, setIsFullscreen] = useState(false);
  const timerRef = useRef<any>(null);
  const [disabledOptions, setDisabledOptions] = useState<PieceType[]>([]);
  const [pulsingPiece, setPulsingPiece] = useState<PieceType | null>(null);
  const [moveFeedback, setMoveFeedback] = useState<{ type: PieceType; status: 'correct' | 'incorrect' } | null>(null);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch((err) => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };

    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const generateNewTarget = useCallback((currentPieces: Piece[]) => {
    const randomPiece = currentPieces[Math.floor(Math.random() * currentPieces.length)];
    const legalMoves = getLegalMoves(randomPiece.square, randomPiece.type);
    const availableTargets = legalMoves.filter(m => !currentPieces.some(p => p.square === m));

    if (availableTargets.length === 0) {
      return legalMoves[Math.floor(Math.random() * legalMoves.length)];
    }

    return availableTargets[Math.floor(Math.random() * availableTargets.length)];
  }, []);

  const startGame = (diff: Difficulty) => {
    let pieceCount = 2;
    if (diff === Difficulty.INTERMEDIATE) pieceCount = 3;
    if (diff === Difficulty.HARD) pieceCount = 4;

    const availableTypes: PieceType[] = ['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'];
    const shuffledTypes = [...availableTypes].sort(() => Math.random() - 0.5);
    const selectedTypes = shuffledTypes.slice(0, pieceCount);

    const selectedPieces: Piece[] = [];
    const usedSquares: number[] = [];

    selectedTypes.forEach((type, i) => {
      const square = getRandomSquare(usedSquares);
      usedSquares.push(square);
      selectedPieces.push({
        id: `p-${i}`,
        type,
        square,
        isVisible: true
      });
    });

    setState({
      phase: 'OBSERVING',
      difficulty: diff,
      pieces: selectedPieces,
      targetSquare: null,
      score: 0,
      strikes: 0,
      timeLeft: START_TIME,
      lastMoveLine: null,
      correctMoves: 0,
      currentStreak: 0,
      bestStreak: 0,
    });

    setTimeout(() => {
      setState(prev => {
        const nextTarget = generateNewTarget(prev.pieces);
        return {
          ...prev,
          phase: 'PLAYING',
          pieces: prev.pieces.map(p => ({ ...p, isVisible: false })),
          targetSquare: nextTarget,
        };
      });
    }, OBSERVATION_TIME * 1000);
  };

  useEffect(() => {
    if (state.phase === 'PLAYING') {
      timerRef.current = setInterval(() => {
        setState(prev => {
          if (prev.timeLeft <= 1) {
            clearInterval(timerRef.current!);
            return { ...prev, timeLeft: 0, phase: 'GAMEOVER' };
          }
          return { ...prev, timeLeft: prev.timeLeft - 1 };
        });
      }, 1000);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [state.phase]);

  useEffect(() => {
    if (state.lastMoveLine) {
      const timer = setTimeout(() => {
        setState(prev => ({ ...prev, lastMoveLine: null }));
      }, 1000);
      return () => clearTimeout(timer);
    }
  }, [state.lastMoveLine]);

  useEffect(() => {
    if (moveFeedback) {
      const timer = setTimeout(() => setMoveFeedback(null), 1000);
      return () => clearTimeout(timer);
    }
  }, [moveFeedback]);

  const handlePieceSelect = (type: PieceType) => {
    if (state.phase !== 'PLAYING' || state.targetSquare === null) return;

    const validPiece = state.pieces.find(p => p.type === type && canPieceReach(p.square, state.targetSquare!, p.type));

    if (validPiece) {
      const oldSquare = validPiece.square;
      const newSquare = state.targetSquare!;

      const updatedPieces = state.pieces.map(p => 
        p.id === validPiece.id ? { ...p, square: newSquare } : p
      );

      setDisabledOptions([]);
      setMoveFeedback({ type, status: 'correct' });
      const nextTarget = generateNewTarget(updatedPieces);

      setState(prev => {
        const newStreak = prev.currentStreak + 1;
        return {
          ...prev,
          score: prev.score + 10,
          pieces: updatedPieces,
          lastMoveLine: [oldSquare, newSquare],
          targetSquare: nextTarget,
          correctMoves: prev.correctMoves + 1,
          currentStreak: newStreak,
          bestStreak: Math.max(prev.bestStreak, newStreak),
        };
      });
    } else {
      setPulsingPiece(type);
      setMoveFeedback({ type, status: 'incorrect' });
      setTimeout(() => setPulsingPiece(null), 400);

      setDisabledOptions(prev => [...prev, type]);
      setState(prev => {
        const newStrikes = prev.strikes + 1;
        if (newStrikes >= MAX_STRIKES) {
          clearInterval(timerRef.current!);
          return { ...prev, strikes: newStrikes, phase: 'GAMEOVER', currentStreak: 0 };
        }
        return { ...prev, strikes: newStrikes, currentStreak: 0 };
      });
    }
  };

  const calculateGrade = () => {
    const accuracy = state.correctMoves / (state.correctMoves + state.strikes || 1);
    const score = state.score;

    if (score >= 200 && accuracy >= 0.9) return { rank: 'S', label: 'Grandmaster Sight', desc: 'Flawless board tracking. Your visualization capacity exceeds standard academy metrics.' };
    if (score >= 150 && accuracy >= 0.8) return { rank: 'A', label: 'Masterful Control', desc: 'High accuracy and speed. You possess a strong mental grasp of board dynamics.' };
    if (score >= 80) return { rank: 'B', label: 'Tactical Competence', desc: 'Solid performance. Continue drilling to reduce tracking errors under time pressure.' };
    if (score >= 40) return { rank: 'C', label: 'Developing Vision', desc: 'Basic visualization established. Focus on identifying piece paths more consistently.' };
    return { rank: 'D', label: 'Vision Under Review', desc: 'Concentrate on static board memory before attempting rapid sequence tracking.' };
  };

  const renderStartScreen = () => (
    <div className="flex flex-col items-center justify-center min-h-[80vh] space-y-12 animate-in fade-in duration-1000">
      <div className="text-center">
        <h1 
          className="text-5xl font-extralight tracking-[0.3em] mb-4 uppercase"
          style={{ color: PALETTE.PRIMARY_TEXT }}
        >Academy Drill</h1>
        <p 
          className="font-bold tracking-[0.5em] text-[10px] uppercase"
          style={{ color: PALETTE.HIGHLIGHT_OUTLINE }}
        >Venture Chess Visualization Trainer</p>
      </div>

      <div className="grid grid-cols-1 gap-4 w-72">
        {[
          { id: Difficulty.EASY, label: 'Level I: Two Pieces' },
          { id: Difficulty.INTERMEDIATE, label: 'Level II: Three Pieces' },
          { id: Difficulty.HARD, label: 'Level III: Four Pieces' }
        ].map(diff => (
          <button 
            key={diff.id}
            onClick={() => startGame(diff.id)}
            className="border py-4 px-6 transition-all uppercase tracking-[0.2em] text-[10px] font-bold shadow-sm"
            style={{ 
              backgroundColor: PALETTE.SECONDARY_BG,
              borderColor: PALETTE.MUTED_ELEMENTS,
              color: PALETTE.MUTED_ELEMENTS
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.backgroundColor = PALETTE.PRIMARY_TEXT;
              e.currentTarget.style.color = '#FFFFFF';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.backgroundColor = PALETTE.SECONDARY_BG;
              e.currentTarget.style.color = PALETTE.MUTED_ELEMENTS;
            }}
          >
            {diff.label}
          </button>
        ))}
      </div>
    </div>
  );

  const renderGameScreen = () => (
    <div className="flex flex-col items-center w-full max-w-6xl px-4 animate-in fade-in duration-500 pb-20">
      <div className="w-full max-w-[620px] mt-8 mb-4 font-mono select-none">
        <div className="flex justify-between items-end pb-3 px-2">
          <div className="flex space-x-16">
            <div className="flex flex-col">
              <span className="text-[10px] font-bold tracking-widest uppercase mb-2 opacity-60" style={{ color: PALETTE.PRIMARY_TEXT }}>SCORE</span>
              <span className="text-2xl font-black tracking-tight" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.score.toString().padStart(4, '0')}</span>
            </div>
            <div className="flex flex-col">
              <span className="text-[10px] font-bold tracking-widest uppercase mb-2 opacity-60" style={{ color: PALETTE.PRIMARY_TEXT }}>TIME</span>
              <span className="text-2xl font-black tracking-tight" style={{ color: state.timeLeft < 15 ? '#EF4444' : PALETTE.PRIMARY_TEXT }}>
                {Math.floor(state.timeLeft / 60)}:{(state.timeLeft % 60).toString().padStart(2, '0')}
              </span>
            </div>
          </div>

          <div className="flex flex-col items-end">
            <span className="text-[10px] font-bold tracking-widest uppercase mb-3 opacity-60" style={{ color: PALETTE.PRIMARY_TEXT }}>STRIKES</span>
            <div className="flex space-x-2">
              {Array.from({ length: MAX_STRIKES }).map((_, i) => (
                <div 
                  key={i} 
                  className="w-8 h-1.5 transition-all duration-300"
                  style={{ 
                    backgroundColor: i < state.strikes ? '#EF4444' : `${PALETTE.MUTED_ELEMENTS}25`,
                    transform: i < state.strikes ? 'scaleY(1.2)' : 'scaleY(1)'
                  }} 
                />
              ))}
            </div>
          </div>
        </div>
        <div className="w-full h-[1px] opacity-20" style={{ backgroundColor: PALETTE.PRIMARY_TEXT }} />
      </div>

      <ChessBoard 
        pieces={state.pieces} 
        targetSquare={state.targetSquare} 
        lastMoveLine={state.lastMoveLine} 
      />

      <div className="mt-10 flex flex-col items-center w-full max-w-[620px]">
        <div 
          className="flex justify-center space-x-4 w-full p-6 border rounded-sm"
          style={{ 
            borderColor: `${PALETTE.MUTED_ELEMENTS}10`,
            backgroundColor: PALETTE.SECONDARY_BG,
            opacity: state.phase !== 'PLAYING' ? 0.2 : 1 
          }}
        >
          {(['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'] as PieceType[]).map((type) => {
            const isUsedInSession = state.pieces.some(p => p.type === type);
            const isDisabled = disabledOptions.includes(type);
            const isPulsing = pulsingPiece === type;
            const feedback = moveFeedback?.type === type ? moveFeedback : null;

            if (!isUsedInSession) return null;

            return (
              <button
                key={type}
                onClick={() => handlePieceSelect(type)}
                disabled={isDisabled}
                className={`relative w-28 h-32 p-3 border transition-all active:scale-95 flex flex-col items-center justify-between rounded-sm ${isPulsing ? 'animate-subtle-pulse' : ''}`}
                style={{ 
                  backgroundColor: PALETTE.SECONDARY_BG,
                  borderColor: isPulsing ? '#EF4444' : `${PALETTE.MUTED_ELEMENTS}20`,
                  opacity: isDisabled && !feedback && !isPulsing ? 0.3 : 1,
                  boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)'
                }}
              >
                {feedback && (
                  <div className={`absolute inset-0 flex items-center justify-center z-10 rounded-sm bg-white/40 backdrop-blur-[1px] animate-in fade-in duration-200`}>
                    {feedback.status === 'correct' ? (
                      <svg className="w-12 h-12 text-green-500 drop-shadow-sm" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="4">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                      </svg>
                    ) : (
                      <svg className="w-12 h-12 text-red-500 drop-shadow-sm" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="4">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                      </svg>
                    )}
                  </div>
                )}

                <div className="w-full h-20 flex items-center justify-center">
                  <div className="w-16 h-16">
                    {PIECE_ICONS[type]}
                  </div>
                </div>
                <span className="text-[11px] font-bold uppercase tracking-widest pt-2 border-t w-full text-center" style={{ color: PALETTE.MUTED_ELEMENTS, borderColor: `${PALETTE.MUTED_ELEMENTS}10` }}>{type}</span>
              </button>
            );
          })}
        </div>

        <div 
          className="mt-8 text-[11px] font-bold uppercase tracking-[0.5em] text-center opacity-60"
          style={{ color: state.phase === 'OBSERVING' ? PALETTE.HIGHLIGHT_OUTLINE : PALETTE.PRIMARY_TEXT }}
        >
          {state.phase === 'OBSERVING' ? 'MEMORIZE PIECE LOCATIONS' : 'CHOOSE THE PIECE THAT CAN REACH THE HIGHLIGHTED SQUARE'}
        </div>
      </div>
    </div>
  );

  const renderGameOver = () => {
    const grade = calculateGrade();
    return (
      <div className="flex flex-col items-center justify-center min-h-[90vh] py-12 px-4 space-y-10 animate-in fade-in zoom-in duration-700 max-w-2xl text-center">
        <div className="space-y-2">
          <h2 className="text-4xl font-extralight tracking-[0.3em] uppercase" style={{ color: PALETTE.PRIMARY_TEXT }}>Drill Analysis</h2>
          <div className="h-0.5 w-16 bg-blue-500 mx-auto opacity-50" />
        </div>

        <div className="flex flex-col items-center space-y-4">
          <div 
            className="w-32 h-32 rounded-full border-4 flex items-center justify-center text-6xl font-black shadow-xl animate-bounce-subtle"
            style={{ 
              borderColor: PALETTE.HIGHLIGHT_OUTLINE, 
              color: PALETTE.HIGHLIGHT_OUTLINE,
              backgroundColor: '#FFFFFF'
            }}
          >
            {grade.rank}
          </div>
          <div className="space-y-1">
            <p className="uppercase tracking-[0.4em] text-[12px] font-black" style={{ color: PALETTE.PRIMARY_TEXT }}>{grade.label}</p>
            <p className="text-xs text-slate-500 max-w-xs mx-auto leading-relaxed">{grade.desc}</p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4 w-full max-w-md">
          <div className="p-6 bg-white border border-slate-200 rounded-sm shadow-sm flex flex-col items-center justify-center space-y-1">
            <span className="uppercase tracking-[0.2em] text-[8px] font-bold opacity-60">Total Score</span>
            <span className="text-3xl font-black tracking-tight" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.score}</span>
          </div>
          <div className="p-6 bg-white border border-slate-200 rounded-sm shadow-sm flex flex-col items-center justify-center space-y-1">
            <span className="uppercase tracking-[0.2em] text-[8px] font-bold opacity-60">Peak Streak</span>
            <span className="text-3xl font-black tracking-tight" style={{ color: PALETTE.HIGHLIGHT_OUTLINE }}>{state.bestStreak}</span>
          </div>
          <div className="p-4 bg-white border border-slate-200 rounded-sm shadow-sm flex justify-between items-center w-full col-span-2">
            <span className="uppercase tracking-[0.2em] text-[9px] font-bold opacity-60">Successful Visualizations</span>
            <span className="text-sm font-mono font-bold" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.correctMoves}</span>
          </div>
        </div>

        <div className="flex flex-col sm:flex-row space-y-4 sm:space-y-0 sm:space-x-6 pt-6">
          <button 
            onClick={() => startGame(state.difficulty)}
            className="border py-4 px-12 text-[10px] font-bold uppercase tracking-[0.3em] transition-all hover:bg-slate-50 shadow-sm rounded-sm"
            style={{ borderColor: PALETTE.MUTED_ELEMENTS, color: PALETTE.PRIMARY_TEXT }}
          >
            New Session
          </button>
          <button 
            onClick={() => setState(prev => ({ ...prev, phase: 'START' }))}
            className="py-4 px-12 text-[10px] font-bold uppercase tracking-[0.3em] transition-all hover:opacity-90 shadow-lg rounded-sm"
            style={{ backgroundColor: PALETTE.PRIMARY_TEXT, color: '#FFFFFF' }}
          >
            Academy Hub
          </button>
        </div>
      </div>
    );
  };

  return (
    <div className="relative min-h-screen w-full flex flex-col items-center overflow-x-hidden" style={{ backgroundColor: PALETTE.PRIMARY_BG }}>
      <button 
        onClick={toggleFullscreen}
        className="fixed top-8 right-8 z-50 p-3 bg-white border border-gray-200 shadow-sm rounded-sm hover:bg-gray-50 transition-colors group"
        title={isFullscreen ? "Exit Fullscreen" : "Enter Fullscreen"}
      >
        {isFullscreen ? (
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={PALETTE.PRIMARY_TEXT} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M8 3v3a2 2 0 0 1-2 2H3m18 0h-3a2 2 0 0 1-2-2V3m0 18v-3a2 2 0 0 1 2-2h3M3 16h3a2 2 0 0 1 2 2v3"/>
          </svg>
        ) : (
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={PALETTE.PRIMARY_TEXT} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M15 3h6v6M9 21H3v-6M21 3l-7 7M3 21l7-7"/>
          </svg>
        )}
      </button>

      <main className="relative z-20 w-full h-full flex flex-col items-center flex-grow">
        {state.phase === 'START' && renderStartScreen()}
        {(state.phase === 'OBSERVING' || state.phase === 'PLAYING') && renderGameScreen()}
        {state.phase === 'GAMEOVER' && renderGameOver()}
      </main>

      <div className="fixed top-8 left-8 flex flex-col opacity-20 pointer-events-none hidden xl:flex">
        <div className="text-[10px] font-bold uppercase tracking-[1em]" style={{ color: PALETTE.MUTED_ELEMENTS }}>Venture</div>
        <div className="text-[10px] font-bold uppercase tracking-[1em]" style={{ color: PALETTE.MUTED_ELEMENTS }}>Academy</div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { Piece } from '../types';
import { PALETTE, PIECE_ICONS } from '../constants';

interface ChessBoardProps {
  pieces: Piece[];
  targetSquare: number | null;
  lastMoveLine: [number, number] | null;
}

const ChessBoard: React.FC<ChessBoardProps> = ({ pieces, targetSquare, lastMoveLine }) => {
  const ranks = ['8', '7', '6', '5', '4', '3', '2', '1'];
  const files = ['a', 'b', 'c', 'd', 'e', 'f', 'g', 'h'];

  const getSquareColor = (idx: number) => {
    const row = Math.floor(idx / 8);
    const col = idx % 8;
    return (row + col) % 2 === 0 ? PALETTE.BOARD_LIGHT : PALETTE.BOARD_DARK;
  };

  const getCoordinatesForLine = (idx: number) => {
    const row = Math.floor(idx / 8);
    const col = idx % 8;
    return {
      x: col * 12.5 + 6.25,
      y: row * 12.5 + 6.25,
    };
  };

  return (
    <div 
      className="relative flex rounded-sm overflow-hidden"
      style={{ 
        backgroundColor: '#CED4D9',
        boxShadow: '0 15px 25px -5px rgb(0 0 0 / 0.15), 0 8px 10px -6px rgb(0 0 0 / 0.1)'
      }}
    >
      {/* Left Ranks Gutters - Lichess Style */}
      <div className="flex flex-col w-5 sm:w-7 h-[320px] sm:h-[440px] md:h-[540px] bg-[#CED4D9]">
        {ranks.map(r => (
          <div key={r} className="flex-1 flex items-center justify-center">
            <span className="text-[10px] font-bold text-[#64748B] antialiased select-none">{r}</span>
          </div>
        ))}
      </div>

      <div className="flex flex-col">
        <div 
          className="relative aspect-square w-[320px] sm:w-[440px] md:w-[540px] border border-gray-400/30 overflow-hidden select-none bg-white"
        >
          {/* 8x8 Chessboard */}
          <div className="grid grid-cols-8 grid-rows-8 w-full h-full">
            {Array.from({ length: 64 }).map((_, i) => (
              <div
                key={i}
                style={{ backgroundColor: getSquareColor(i) }}
                className="relative flex items-center justify-center transition-colors duration-200"
              >
                {/* Highlighted Target Square - Enhanced visualization */}
                {targetSquare === i && (
                  <div 
                    className="absolute inset-0 bg-blue-500/30 border-[4px] pointer-events-none z-10 animate-pulse-slow" 
                    style={{ borderColor: PALETTE.HIGHLIGHT_OUTLINE }}
                  />
                )}
              </div>
            ))}
          </div>

          {/* Pieces Layer */}
          <div className="absolute inset-0 grid grid-cols-8 grid-rows-8 pointer-events-none">
            {Array.from({ length: 64 }).map((_, i) => {
              const piece = pieces.find((p) => p.square === i);
              return (
                <div key={i} className="flex items-center justify-center p-0.5">
                  {piece && piece.isVisible && (
                    <div className="w-[90%] h-[90%] flex items-center justify-center animate-in fade-in zoom-in duration-300">
                      {PIECE_ICONS[piece.type]}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          {/* Move Line Layer with Fading Arrow */}
          {lastMoveLine && (
            <svg key={`${lastMoveLine[0]}-${lastMoveLine[1]}`} className="absolute inset-0 w-full h-full pointer-events-none z-20" viewBox="0 0 100 100">
              <defs>
                <marker id="arrowhead" markerWidth="4" markerHeight="4" refX="2" refY="2" orient="auto">
                  <polygon points="0 0, 4 2, 0 4" fill={PALETTE.PATH_INDICATOR} opacity="0.6" />
                </marker>
              </defs>
              <line
                x1={getCoordinatesForLine(lastMoveLine[0]).x}
                y1={getCoordinatesForLine(lastMoveLine[0]).y}
                x2={getCoordinatesForLine(lastMoveLine[1]).x}
                y2={getCoordinatesForLine(lastMoveLine[1]).y}
                stroke={PALETTE.PATH_INDICATOR}
                strokeWidth="1.2"
                strokeLinecap="round"
                markerEnd="url(#arrowhead)"
                className="animate-line-fade"
                style={{ strokeDasharray: '0.5, 2' }}
              />
            </svg>
          )}
        </div>

        {/* Bottom Files Gutter - Lichess Style */}
        <div className="flex w-full h-5 sm:h-7 bg-[#CED4D9]">
          {files.map(f => (
            <div key={f} className="flex-1 flex items-center justify-center">
              <span className="text-[10px] font-bold text-[#64748B] antialiased select-none">{f}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ChessBoard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, GamePhase, Difficulty, Piece, PieceType } from './types';
import { getRandomSquare, getLegalMoves, canPieceReach } from './services/chessLogic';
import { PALETTE, PIECE_ICONS } from './constants';
import ChessBoard from './components/ChessBoard';

const OBSERVATION_TIME = 5;
const START_TIME = 180; 
const MAX_STRIKES = 5;

const App: React.FC = () => {
  const [state, setState] = useState<GameState>({
    phase: 'START',
    difficulty: Difficulty.EASY,
    pieces: [],
    targetSquare: null,
    score: 0,
    strikes: 0,
    timeLeft: START_TIME,
    lastMoveLine: null,
    correctMoves: 0,
    currentStreak: 0,
    bestStreak: 0,
  });

  const [isFullscreen, setIsFullscreen] = useState(false);
  const timerRef = useRef<any>(null);
  const [disabledOptions, setDisabledOptions] = useState<PieceType[]>([]);
  const [pulsingPiece, setPulsingPiece] = useState<PieceType | null>(null);
  const [moveFeedback, setMoveFeedback] = useState<{ type: PieceType; status: 'correct' | 'incorrect' } | null>(null);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch((err) => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };

    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const generateNewTarget = useCallback((currentPieces: Piece[]) => {
    const randomPiece = currentPieces[Math.floor(Math.random() * currentPieces.length)];
    const legalMoves = getLegalMoves(randomPiece.square, randomPiece.type);
    const availableTargets = legalMoves.filter(m => !currentPieces.some(p => p.square === m));

    if (availableTargets.length === 0) {
      return legalMoves[Math.floor(Math.random() * legalMoves.length)];
    }

    return availableTargets[Math.floor(Math.random() * availableTargets.length)];
  }, []);

  const startGame = (diff: Difficulty) => {
    let pieceCount = 2;
    if (diff === Difficulty.INTERMEDIATE) pieceCount = 3;
    if (diff === Difficulty.HARD) pieceCount = 4;

    // Use only unique piece types from the Cburnett set
    const availableTypes: PieceType[] = ['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'];
    const shuffledTypes = [...availableTypes].sort(() => Math.random() - 0.5);
    const selectedTypes = shuffledTypes.slice(0, pieceCount);

    const selectedPieces: Piece[] = [];
    const usedSquares: number[] = [];

    selectedTypes.forEach((type, i) => {
      const square = getRandomSquare(usedSquares);
      usedSquares.push(square);
      selectedPieces.push({
        id: `p-${i}`,
        type,
        square,
        isVisible: true
      });
    });

    setState({
      phase: 'OBSERVING',
      difficulty: diff,
      pieces: selectedPieces,
      targetSquare: null,
      score: 0,
      strikes: 0,
      timeLeft: START_TIME,
      lastMoveLine: null,
      correctMoves: 0,
      currentStreak: 0,
      bestStreak: 0,
    });

    setTimeout(() => {
      setState(prev => {
        const nextTarget = generateNewTarget(prev.pieces);
        return {
          ...prev,
          phase: 'PLAYING',
          pieces: prev.pieces.map(p => ({ ...p, isVisible: false })),
          targetSquare: nextTarget,
        };
      });
    }, OBSERVATION_TIME * 1000);
  };

  useEffect(() => {
    if (state.phase === 'PLAYING') {
      timerRef.current = setInterval(() => {
        setState(prev => {
          if (prev.timeLeft <= 1) {
            clearInterval(timerRef.current!);
            return { ...prev, timeLeft: 0, phase: 'GAMEOVER' };
          }
          return { ...prev, timeLeft: prev.timeLeft - 1 };
        });
      }, 1000);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [state.phase]);

  useEffect(() => {
    if (state.lastMoveLine) {
      const timer = setTimeout(() => {
        setState(prev => ({ ...prev, lastMoveLine: null }));
      }, 1000);
      return () => clearTimeout(timer);
    }
  }, [state.lastMoveLine]);

  useEffect(() => {
    if (moveFeedback) {
      const timer = setTimeout(() => setMoveFeedback(null), 1000);
      return () => clearTimeout(timer);
    }
  }, [moveFeedback]);

  const handlePieceSelect = (type: PieceType) => {
    if (state.phase !== 'PLAYING' || state.targetSquare === null) return;

    const validPiece = state.pieces.find(p => p.type === type && canPieceReach(p.square, state.targetSquare!, p.type));

    if (validPiece) {
      const oldSquare = validPiece.square;
      const newSquare = state.targetSquare!;

      const updatedPieces = state.pieces.map(p => 
        p.id === validPiece.id ? { ...p, square: newSquare } : p
      );

      setDisabledOptions([]);
      setMoveFeedback({ type, status: 'correct' });
      const nextTarget = generateNewTarget(updatedPieces);

      setState(prev => {
        const newStreak = prev.currentStreak + 1;
        return {
          ...prev,
          score: prev.score + 10,
          pieces: updatedPieces,
          lastMoveLine: [oldSquare, newSquare],
          targetSquare: nextTarget,
          correctMoves: prev.correctMoves + 1,
          currentStreak: newStreak,
          bestStreak: Math.max(prev.bestStreak, newStreak),
        };
      });
    } else {
      setPulsingPiece(type);
      setMoveFeedback({ type, status: 'incorrect' });
      setTimeout(() => setPulsingPiece(null), 400);

      setDisabledOptions(prev => [...prev, type]);
      setState(prev => {
        const newStrikes = prev.strikes + 1;
        if (newStrikes >= MAX_STRIKES) {
          clearInterval(timerRef.current!);
          return { ...prev, strikes: newStrikes, phase: 'GAMEOVER', currentStreak: 0 };
        }
        return { ...prev, strikes: newStrikes, currentStreak: 0 };
      });
    }
  };

  const calculateGrade = () => {
    const accuracy = state.correctMoves / (state.correctMoves + state.strikes || 1);
    const score = state.score;

    if (score >= 200 && accuracy >= 0.9) return { rank: 'S', label: 'Grandmaster Sight', desc: 'Flawless board tracking. Your visualization capacity exceeds standard academy metrics.' };
    if (score >= 150 && accuracy >= 0.8) return { rank: 'A', label: 'Masterful Control', desc: 'High accuracy and speed. You possess a strong mental grasp of board dynamics.' };
    if (score >= 80) return { rank: 'B', label: 'Tactical Competence', desc: 'Solid performance. Continue drilling to reduce tracking errors under time pressure.' };
    if (score >= 40) return { rank: 'C', label: 'Developing Vision', desc: 'Basic visualization established. Focus on identifying piece paths more consistently.' };
    return { rank: 'D', label: 'Vision Under Review', desc: 'Concentrate on static board memory before attempting rapid sequence tracking.' };
  };

  const renderStartScreen = () => (
    <div className="flex flex-col items-center justify-center min-h-[80vh] space-y-12 animate-in fade-in duration-1000">
      <div className="text-center">
        <h1 
          className="text-5xl font-extralight tracking-[0.3em] mb-4 uppercase"
          style={{ color: PALETTE.PRIMARY_TEXT }}
        >Academy Drill</h1>
        <p 
          className="font-bold tracking-[0.5em] text-[10px] uppercase"
          style={{ color: PALETTE.HIGHLIGHT_OUTLINE }}
        >Venture Chess Visualization Trainer</p>
      </div>

      <div className="grid grid-cols-1 gap-4 w-72">
        {[
          { id: Difficulty.EASY, label: 'Level I: Two Pieces' },
          { id: Difficulty.INTERMEDIATE, label: 'Level II: Three Pieces' },
          { id: Difficulty.HARD, label: 'Level III: Four Pieces' }
        ].map(diff => (
          <button 
            key={diff.id}
            onClick={() => startGame(diff.id)}
            className="border py-4 px-6 transition-all uppercase tracking-[0.2em] text-[10px] font-bold shadow-sm"
            style={{ 
              backgroundColor: PALETTE.SECONDARY_BG,
              borderColor: PALETTE.MUTED_ELEMENTS,
              color: PALETTE.MUTED_ELEMENTS
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.backgroundColor = PALETTE.PRIMARY_TEXT;
              e.currentTarget.style.color = '#FFFFFF';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.backgroundColor = PALETTE.SECONDARY_BG;
              e.currentTarget.style.color = PALETTE.MUTED_ELEMENTS;
            }}
          >
            {diff.label}
          </button>
        ))}
      </div>
    </div>
  );

  const renderGameScreen = () => (
    <div className="flex flex-col items-center w-full max-w-6xl px-4 animate-in fade-in duration-500 pb-20">
      <div className="w-full max-w-[620px] mt-8 mb-4 font-mono select-none">
        <div className="flex justify-between items-end pb-3 px-2">
          <div className="flex space-x-16">
            <div className="flex flex-col">
              <span className="text-[10px] font-bold tracking-widest uppercase mb-2 opacity-60" style={{ color: PALETTE.PRIMARY_TEXT }}>SCORE</span>
              <span className="text-2xl font-black tracking-tight" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.score.toString().padStart(4, '0')}</span>
            </div>
            <div className="flex flex-col">
              <span className="text-[10px] font-bold tracking-widest uppercase mb-2 opacity-60" style={{ color: PALETTE.PRIMARY_TEXT }}>TIME</span>
              <span className="text-2xl font-black tracking-tight" style={{ color: state.timeLeft < 15 ? '#EF4444' : PALETTE.PRIMARY_TEXT }}>
                {Math.floor(state.timeLeft / 60)}:{(state.timeLeft % 60).toString().padStart(2, '0')}
              </span>
            </div>
          </div>

