          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={PALETTE.PRIMARY_TEXT} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
