interface ChessBoardProps {
  fen: string;
  isVisible: boolean;
  targetSquare: string | null;
  onMove?: (sourceSquare: string, targetSquare: string) => boolean;
  lastMove?: { from: string; to: string };
}

const ChessBoard: React.FC<ChessBoardProps> = ({ fen, isVisible, targetSquare, onMove, lastMove }) => {
  const customSquareStyles: any = {};

  if (targetSquare) {
    customSquareStyles[targetSquare] = {
      background: 'rgba(255, 255, 0, 0.4)',
      boxShadow: 'inset 0 0 0 4px rgba(255, 255, 0, 0.8)'
    };
  }

  if (lastMove) {
    customSquareStyles[lastMove.from] = { background: 'rgba(255, 255, 0, 0.2)' };
    customSquareStyles[lastMove.to] = { background: 'rgba(255, 255, 0, 0.2)' };
  }

  return (
    <div className="w-full aspect-square shadow-2xl rounded-sm overflow-hidden border border-[#403d39]">
      <Chessboard 
        position={isVisible ? fen : '8/8/8/8/8/8/8/8'} 
        onPieceDrop={onMove}
        customDarkSquareStyle={{ backgroundColor: PALETTE.BOARD_DARK }}
        customLightSquareStyle={{ backgroundColor: PALETTE.BOARD_LIGHT }}
        customSquareStyles={customSquareStyles}
        animationDuration={200}
        boardOrientation="white"
      />
    </div>
  );
};

