            {phase === 'LOBBY' && (
              <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-black/60 backdrop-blur-sm rounded-sm">
                <Brain className="w-16 h-16 text-[#629924] mb-4" />
