          <div className="mt-8 flex flex-col items-center w-full max-w-[700px]">
             <div className="text-[10px] font-bold uppercase tracking-[0.5em] text-[#bababa] mb-4 opacity-50">Select Payload Identifier</div>
             <div className="flex space-x-4">
                {(['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'] as const).map((type) => {
                  const isFeedbackSource = feedback?.piece === type;
                  return (
                    <button
